// Validar y extraer informe_id
const body = $input.item.json.body || $input.item.json;

if (!body.informe_id) {
  throw new Error('Falta informe_id en el request');
}

return [{
  json: {
    informe_id: body.informe_id
  }
}];

// Obtener el informe del array de respuesta
const respuesta = $input.item.json;
const informe = Array.isArray(respuesta) ? respuesta[0] : respuesta;

if (!informe || !informe.id) {
  throw new Error('No se encontró el informe en Supabase');
}

// Obtener observaciones de la matriz si están en observaciones_enumeradas
let observacionesCompletas = [];
if (informe.observaciones_enumeradas && Array.isArray(informe.observaciones_enumeradas)) {
  observacionesCompletas = informe.observaciones_enumeradas;
}

// Inicializar objetos de usuario vacíos (se completarán si hay IDs)
informe.elaborado_por_user = informe.elaborado_por ? { id: informe.elaborado_por, full_name: null, email: '' } : null;
informe.revisado_por_user = informe.revisado_por ? { id: informe.revisado_por, full_name: null, email: '' } : null;
informe.aprobado_por_user = informe.aprobado_por ? { id: informe.aprobado_por, full_name: null, email: '' } : null;

return [{
  json: {
    informe: informe,
    informe_id: informe.id,
    auditoria_id: informe.auditoria_id,
    observaciones: observacionesCompletas
  }
}];

// Generar contenido HTML del informe (formato Word)
const data = $json;
const informe = data.informe;
const observaciones = data.observaciones || [];

// Formatear fechas
const formatearFecha = (fecha) => {
  if (!fecha) return 'No definida';
  try {
    return new Date(fecha).toLocaleDateString('es-ES', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  } catch {
    return fecha;
  }
};

// Generar HTML con formato de documento Word
const htmlContent = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    @page { margin: 2.5cm; }
    body { 
      font-family: 'Times New Roman', serif; 
      font-size: 12pt; 
      line-height: 1.5; 
      color: #000; 
      margin: 0; 
      padding: 0;
    }
    h1 { 
      text-align: center; 
      border-bottom: 2px solid #000; 
      padding-bottom: 10px; 
      margin-bottom: 30px;
      font-size: 16pt;
      font-weight: bold;
    }
    h2 { 
      border-bottom: 1px solid #333; 
      padding-bottom: 5px; 
      margin-top: 25px;
      margin-bottom: 15px;
      font-size: 14pt;
      font-weight: bold;
    }
    .header { 
      margin-bottom: 30px; 
      line-height: 1.8;
    }
    .header p { margin: 5px 0; }
    .observacion { 
      margin: 20px 0; 
      padding: 15px; 
      border-left: 4px solid #2563eb; 
      background: #f9fafb;
      page-break-inside: avoid;
    }
    .observacion h3 { margin-top: 0; color: #2563eb; }
    .firma { margin-top: 40px; page-break-inside: avoid; }
    .firma p { margin: 10px 0; }
  </style>
</head>
<body>
  <h1>${informe.encabezado || 'INFORME DE AUDITORÍA'}</h1>

  <div class="header">
    <p><strong>De:</strong> ${informe.de || 'No especificado'}</p>
    <p><strong>Para:</strong> ${informe.para || 'No especificado'}</p>
    <p><strong>Asunto:</strong> ${informe.asunto || 'No especificado'}</p>
    <p><strong>Fecha:</strong> ${formatearFecha(informe.fecha_inicio_informe)}</p>
  </div>

  ${informe.antecedentes ? `<h2>1. ANTECEDENTES</h2>
  <p>${informe.antecedentes.replace(/\n/g, '</p><p>')}</p>` : ''}

  ${informe.objetivos ? `<h2>2. OBJETIVOS</h2>
  <p>${informe.objetivos.replace(/\n/g, '</p><p>')}</p>` : ''}

  ${informe.alcance ? `<h2>3. ALCANCE</h2>
  <p>${informe.alcance.replace(/\n/g, '</p><p>')}</p>` : ''}

  ${informe.resultados_revision ? `<h2>4. RESULTADOS DE LA REVISIÓN</h2>
  <p>${informe.resultados_revision.replace(/\n/g, '</p><p>')}</p>` : ''}

  ${informe.metodologia_aplicada ? `<h2>5. METODOLOGÍA APLICADA</h2>
  <p>${informe.metodologia_aplicada.replace(/\n/g, '</p><p>')}</p>` : ''}

  ${observaciones.length > 0 ? `<h2>6. ${informe.titulo_observaciones || 'OBSERVACIONES'}</h2>
  ${observaciones.map((obs, idx) => `
    <div class="observacion">
      <h3>OBSERVACIÓN N° ${obs.numero || idx + 1}</h3>
      ${obs.titulo ? `<p><strong>Título:</strong> ${obs.titulo}</p>` : ''}
      ${obs.descripcion ? `<p><strong>Descripción:</strong> ${obs.descripcion.replace(/\n/g, '</p><p>')}</p>` : ''}
      ${obs.recomendacion ? `<p><strong>Recomendación:</strong> ${obs.recomendacion.replace(/\n/g, '</p><p>')}</p>` : ''}
    </div>
  `).join('')}` : ''}

  ${informe.estrategia ? `<h2>7. ESTRATEGIA DE IMPLEMENTACIÓN</h2>
  <p>${informe.estrategia.replace(/\n/g, '</p><p>')}</p>
  <p><strong>Fecha de inicio:</strong> ${formatearFecha(informe.fecha_inicio_implementacion)}</p>
  <p><strong>Fecha de fin:</strong> ${formatearFecha(informe.fecha_fin_implementacion)}</p>
  ${informe.entregable ? `<p><strong>Entregable:</strong> ${informe.entregable}</p>` : ''}` : ''}

  ${informe.conclusiones ? `<h2>8. CONCLUSIONES</h2>
  <p>${informe.conclusiones.replace(/\n/g, '</p><p>')}</p>` : ''}

  ${informe.recomendaciones_generales ? `<h2>9. RECOMENDACIONES GENERALES</h2>
  <p>${informe.recomendaciones_generales.replace(/\n/g, '</p><p>')}</p>` : ''}

  <div class="firma">
    <h2>FIRMAS</h2>
    <p><strong>Elaborado por:</strong> ${informe.elaborado_por_user?.full_name || 'No especificado'}</p>
    <p><strong>Fecha de elaboración:</strong> ${formatearFecha(informe.fecha_elaboracion)}</p>
    ${informe.aprobado_por_user ? `<p><strong>Aprobado por:</strong> ${informe.aprobado_por_user.full_name}</p>
    <p><strong>Fecha de aprobación:</strong> ${formatearFecha(informe.fecha_aprobacion)}</p>` : ''}
  </div>
</body>
</html>
`;

return [{
  json: {
    informe_id: informe.id,
    auditoria_id: informe.auditoria_id,
    contenido_html: htmlContent,
    contenido: {
      encabezado: informe.encabezado,
      de: informe.de,
      para: informe.para,
      asunto: informe.asunto,
      fecha_inicio: informe.fecha_inicio_informe,
      observaciones_count: observaciones.length
    }
  }
}];

// Preparar datos para crear Google Docs desde HTML
const data = $input.item.json;
const htmlContent = data.contenido_html;

if (!htmlContent) {
  throw new Error('No se encontró contenido_html para generar el documento');
}

// Generar nombre del documento
const nombreDocumento = `${data.contenido?.encabezado || 'Informe'}_${data.contenido?.fecha_inicio || 'SinFecha'}`;

// Preparar HTML limpio (extraer solo el contenido del body)
let htmlLimpio = htmlContent;
// Remover DOCTYPE y tags html/head/body si existen, mantener solo el contenido
htmlLimpio = htmlLimpio.replace(/<!DOCTYPE[^>]*>/gi, '');
htmlLimpio = htmlLimpio.replace(/<html[^>]*>/gi, '');
htmlLimpio = htmlLimpio.replace(/</html>/gi, '');
htmlLimpio = htmlLimpio.replace(/<head[^>]*>([\s\S]*?)<\/head>/gi, '');
htmlLimpio = htmlLimpio.replace(/<body[^>]*>/gi, '');
htmlLimpio = htmlLimpio.replace(/<\/body>/gi, '');
htmlLimpio = htmlLimpio.trim();

// Convertir HTML a Buffer para subir como archivo
const htmlBuffer = Buffer.from(htmlLimpio, 'utf-8');

return [{
  json: {
    ...data,
    documento_generado: true,
    nombre_documento: nombreDocumento,
    contenido_html_limpio: htmlLimpio
  },
  binary: {
    data: {
      data: htmlBuffer.toString('base64'),
      mimeType: 'text/html',
      fileName: `${nombreDocumento}.html`
    }
  }
}];

// Preparar respuesta final
const resultado = {
  success: true,
  informe_id: $('Code - Preparar Datos Informe').item.json.informe_id,
  documento_word_url: $('HTTP Request - Actualizar documento_word_url en Supabase').item.json[0]?.documento_word_url || null,
  mensaje: 'Documento Word generado y guardado en Google Drive. La matriz se actualizará automáticamente cuando el informe cambie a estado COMPLETADO o ENVIADO_A_AUDITADOS (trigger automático).'
};

return [{
  json: resultado
}];
